// ── Churn Probability Scorer ──────────────────────────────────────
// Weights: Login Frequency 30% | Feature Breadth 25% | Recency 25% | Ticket Volume 20%
// Output: churn_score 0-100 (higher = more likely to churn)

const accounts = $input.all();
const now = new Date();

const scored = accounts.map(item => {
  const d = item.json;

  // ── 1. Login Frequency Score (30 pts max, inverse) ──────────────
  // 20+ logins in 90 days = healthy (0 churn pts), 0 logins = max churn pts
  const loginChurn = (1 - Math.min(d.logins_90d / 20, 1)) * 30;

  // ── 2. Feature Breadth Score (25 pts max, inverse) ─────────────
  // 8+ distinct features used = engaged (0 churn pts)
  const featureChurn = (1 - Math.min(d.features_90d / 8, 1)) * 25;

  // ── 3. Recency Score (25 pts max, inverse) ─────────────────────
  // Last login within 7 days = very active (0 pts)
  // No login in 90 days = 25 churn pts
  let recencyChurn = 25;
  if (d.last_login) {
    const daysSince = Math.floor((now - new Date(d.last_login)) / (1000 * 60 * 60 * 24));
    recencyChurn = Math.min(daysSince / 90, 1) * 25;
  }

  // ── 4. Support Ticket Volume (20 pts max) ──────────────────────
  // 3+ tickets in 90 days = high friction (max 20 churn pts)
  const ticketChurn = Math.min(d.tickets_90d / 3, 1) * 20;

  const raw_score = loginChurn + featureChurn + recencyChurn + ticketChurn;
  const churn_score = Math.round(Math.max(0, Math.min(100, raw_score)));

  let churn_risk_level, intervention_type;
  if (churn_score >= 80)      { churn_risk_level = 'critical';  intervention_type = 'executive_call'; }
  else if (churn_score >= 60) { churn_risk_level = 'high';      intervention_type = 'personal_email'; }
  else if (churn_score >= 40) { churn_risk_level = 'medium';    intervention_type = 'automated_sequence'; }
  else                        { churn_risk_level = 'low';       intervention_type = 'none'; }

  return {
    json: {
      ...d,
      churn_score,
      churn_risk_level,
      intervention_type,
      churn_scored_at: now.toISOString()
    }
  };
});

// Sort by churn score descending for Slack summary
return scored.sort((a, b) => b.json.churn_score - a.json.churn_score);

